import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
  useSortable,
  arrayMove,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { GripVertical, ChevronUp, ChevronDown, Pencil, Trash2, Ticket, Target, ListTodo } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { EmptyState } from "../shared/EmptyState.js";
import { cn } from "../../lib/utils.js";
import type { CommitResponse, PlanState, ChessPiece } from "../../api/planTypes.js";

const CHESS_PIECE_ICONS: Record<ChessPiece, string> = {
  KING: "♔", QUEEN: "♕", ROOK: "♖", BISHOP: "♗", KNIGHT: "♘", PAWN: "♙",
};
const CHESS_PIECE_LABELS: Record<ChessPiece, string> = {
  KING: "King", QUEEN: "Queen", ROOK: "Rook", BISHOP: "Bishop", KNIGHT: "Knight", PAWN: "Pawn",
};

interface SortableItemProps {
  readonly commit: CommitResponse;
  readonly rank: number;
  readonly totalCount: number;
  readonly planState: PlanState;
  readonly rcdoLabel?: string;
  readonly isDraft: boolean;
  readonly onEdit: (commit: CommitResponse) => void;
  readonly onDelete: (commitId: string) => void;
  readonly onMoveUp: (commitId: string) => void;
  readonly onMoveDown: (commitId: string) => void;
  readonly onViewLineage?: (commitId: string) => void;
  readonly onCreateTicket?: (commit: CommitResponse) => void;
}

function SortableItem({ commit, rank, totalCount, isDraft, rcdoLabel, onEdit, onDelete, onMoveUp, onMoveDown, onViewLineage, onCreateTicket }: SortableItemProps) {
  const [expanded, setExpanded] = useState(false);
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: commit.id });

  const isFirst = rank === 1;
  const isLast = rank === totalCount;

  return (
    <li
      ref={setNodeRef}
      style={{ transform: CSS.Transform.toString(transform), transition, opacity: isDragging ? 0.5 : 1, position: "relative", zIndex: isDragging ? 1 : undefined }}
      data-testid={`commit-item-${commit.id}`}
      aria-label={`Commit ${rank}: ${commit.title}`}
    >
      <div className="rounded-default border border-border bg-surface p-3">
        {/* Main row */}
        <div className="flex items-start gap-2 flex-wrap">
          {/* Drag handle */}
          {isDraft && (
            <button
              type="button"
              {...attributes}
              {...listeners}
              aria-label={`Drag to reorder commit: ${commit.title}`}
              data-testid={`drag-handle-${commit.id}`}
              className="text-muted hover:text-foreground cursor-grab shrink-0 p-0.5 touch-none"
            >
              <GripVertical className="h-4 w-4" />
            </button>
          )}

          {/* Priority rank badge */}
          <span
            data-testid={`priority-rank-${commit.id}`}
            className="inline-flex h-6 w-6 items-center justify-center rounded-full bg-primary text-primary-foreground text-xs font-bold shrink-0"
          >
            {rank}
          </span>

          {/* Chess piece icon */}
          <span
            title={CHESS_PIECE_LABELS[commit.chessPiece]}
            aria-label={CHESS_PIECE_LABELS[commit.chessPiece]}
            data-testid={`chess-piece-icon-${commit.id}`}
            className="text-lg leading-none shrink-0 select-none"
          >
            {CHESS_PIECE_ICONS[commit.chessPiece]}
          </span>

          {/* Title */}
          <button
            type="button"
            onClick={() => setExpanded((e) => !e)}
            aria-expanded={expanded}
            data-testid={`commit-title-${commit.id}`}
            className="flex-1 bg-transparent border-none cursor-pointer font-semibold font-mono text-sm text-left p-0 text-foreground hover:text-primary transition-colors"
          >
            {commit.title}
          </button>

          {/* Metadata badges */}
          <div className="flex items-center gap-1.5 shrink-0 flex-wrap">
            {commit.estimatePoints != null && (
              <Badge data-testid={`estimate-badge-${commit.id}`} variant="primary">
                {commit.estimatePoints} pt
              </Badge>
            )}
            {commit.workItemId && (
              <Badge data-testid={`ticket-badge-${commit.id}`} variant="default">
                <Ticket className="h-3 w-3" />{commit.workItemId}
              </Badge>
            )}
          </div>

          {/* Action buttons */}
          <div className="flex gap-1 shrink-0">
            {isDraft && (
              <>
                <Button variant="ghost" size="icon" onClick={() => onMoveUp(commit.id)} disabled={isFirst} aria-label={`Move up: ${commit.title}`} data-testid={`move-up-${commit.id}`} className="h-7 w-7">
                  <ChevronUp className="h-3.5 w-3.5" />
                </Button>
                <Button variant="ghost" size="icon" onClick={() => onMoveDown(commit.id)} disabled={isLast} aria-label={`Move down: ${commit.title}`} data-testid={`move-down-${commit.id}`} className="h-7 w-7">
                  <ChevronDown className="h-3.5 w-3.5" />
                </Button>
                <Button variant="secondary" size="sm" onClick={() => onEdit(commit)} aria-label={`Edit commit: ${commit.title}`} data-testid={`edit-commit-${commit.id}`} className="h-7 px-2 text-xs">
                  <Pencil className="h-3 w-3" />Edit
                </Button>
                <Button variant="danger" size="sm" onClick={() => onDelete(commit.id)} aria-label={`Delete commit: ${commit.title}`} data-testid={`delete-commit-${commit.id}`} className="h-7 px-2 text-xs">
                  <Trash2 className="h-3 w-3" />
                </Button>
              </>
            )}
            {onCreateTicket && (
              <Button variant="ghost" size="sm" onClick={() => onCreateTicket(commit)} aria-label={`Create ticket from commit: ${commit.title}`} data-testid={`create-ticket-from-commit-${commit.id}`} className="h-7 px-2 text-xs" title="Create ticket from this commit">
                <Ticket className="h-3 w-3" />
              </Button>
            )}
          </div>
        </div>

        {/* RCDO path */}
        {rcdoLabel && (
          <div data-testid={`rcdo-path-${commit.id}`} className={cn("mt-1.5 text-xs font-mono text-muted flex items-center gap-1", isDraft ? "ml-12" : "ml-10")}>
            <Target className="h-3 w-3 shrink-0" aria-hidden="true" />{rcdoLabel}
          </div>
        )}

        {/* Inline expanded detail */}
        {expanded && (
          <div data-testid={`commit-detail-${commit.id}`} className="mt-3 pt-3 border-t border-border flex flex-col gap-2 text-sm">
            {commit.description && (
              <div>
                <span className="block text-xs font-semibold uppercase tracking-wider text-muted mb-1">Description</span>
                <p className="m-0 whitespace-pre-wrap" data-testid={`commit-description-${commit.id}`}>{commit.description}</p>
              </div>
            )}
            {commit.successCriteria && (
              <div>
                <span className="block text-xs font-semibold uppercase tracking-wider text-muted mb-1">Success Criteria</span>
                <p className="m-0" data-testid={`commit-sc-${commit.id}`}>{commit.successCriteria}</p>
              </div>
            )}
            {commit.carryForwardStreak > 0 && (
              <div data-testid={`carry-forward-streak-${commit.id}`} className="flex items-center justify-between gap-2 rounded-default bg-neutral-100 px-3 py-1.5 text-xs text-foreground">
                <span>🔁 Carried forward {commit.carryForwardStreak} time{commit.carryForwardStreak !== 1 ? "s" : ""}</span>
                {onViewLineage && (
                  <Button variant="ghost" size="sm" onClick={(e) => { e.stopPropagation(); onViewLineage(commit.id); }} data-testid={`view-lineage-btn-${commit.id}`} className="h-6 px-2 text-xs border border-neutral-300 text-foreground hover:bg-neutral-200">
                    View lineage
                  </Button>
                )}
              </div>
            )}
          </div>
        )}
      </div>
    </li>
  );
}

export interface CommitListProps {
  readonly commits: CommitResponse[];
  readonly planState: PlanState;
  readonly onReorder: (orderedIds: string[]) => void;
  readonly onEdit: (commit: CommitResponse) => void;
  readonly onDelete: (commitId: string) => void;
  readonly rcdoLabels?: Record<string, string>;
  readonly onViewLineage?: (commitId: string) => void;
  readonly onCreateTicket?: (commit: CommitResponse) => void;
  readonly onAddCommit?: () => void;
}

export function CommitList({ commits, planState, onReorder, onEdit, onDelete, rcdoLabels = {}, onViewLineage, onCreateTicket, onAddCommit }: CommitListProps) {
  const isDraft = planState === "DRAFT";
  const [localCommits, setLocalCommits] = useState<CommitResponse[]>(() => [...commits].sort((a, b) => a.priorityOrder - b.priorityOrder));

  const incomingIdsKey = useMemo(() => commits.map((c) => c.id).slice().sort().join(","), [commits]);
  useEffect(() => {
    setLocalCommits([...commits].sort((a, b) => a.priorityOrder - b.priorityOrder));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [incomingIdsKey]);

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    setLocalCommits((prev) => {
      const oldIndex = prev.findIndex((c) => c.id === active.id);
      const newIndex = prev.findIndex((c) => c.id === over.id);
      const reordered = arrayMove(prev, oldIndex, newIndex);
      onReorder(reordered.map((c) => c.id));
      return reordered;
    });
  }, [onReorder]);

  const handleMoveUp = useCallback((commitId: string) => {
    setLocalCommits((prev) => {
      const idx = prev.findIndex((c) => c.id === commitId);
      if (idx <= 0) return prev;
      const reordered = arrayMove(prev, idx, idx - 1);
      onReorder(reordered.map((c) => c.id));
      return reordered;
    });
  }, [onReorder]);

  const handleMoveDown = useCallback((commitId: string) => {
    setLocalCommits((prev) => {
      const idx = prev.findIndex((c) => c.id === commitId);
      if (idx < 0 || idx >= prev.length - 1) return prev;
      const reordered = arrayMove(prev, idx, idx + 1);
      onReorder(reordered.map((c) => c.id));
      return reordered;
    });
  }, [onReorder]);

  if (localCommits.length === 0) {
    return (
      <EmptyState
        data-testid="commit-list-empty"
        icon={<ListTodo className="h-9 w-9" />}
        title={isDraft ? "No commits yet" : "No commits in this plan."}
        {...(isDraft
          ? {
              description: "Add your first commitment to start planning your week.",
            }
          : {})}
        {...(isDraft && onAddCommit
          ? {
              action: (
                <Button variant="primary" onClick={onAddCommit} data-testid="commit-list-add-btn">
                  + Add Commit
                </Button>
              ),
            }
          : {})}
      />
    );
  }

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={localCommits.map((c) => c.id)} strategy={verticalListSortingStrategy}>
        <ol data-testid="commit-list" aria-label="Weekly commits" className="list-none m-0 p-0 flex flex-col gap-2">
          {localCommits.map((commit, index) => {
            const rcdoLabel = commit.rcdoNodeId != null ? rcdoLabels[commit.rcdoNodeId] : undefined;
            return (
              <SortableItem
                key={commit.id}
                commit={commit}
                rank={index + 1}
                totalCount={localCommits.length}
                planState={planState}
                isDraft={isDraft}
                {...(rcdoLabel !== undefined ? { rcdoLabel } : {})}
                onEdit={onEdit}
                onDelete={onDelete}
                onMoveUp={handleMoveUp}
                onMoveDown={handleMoveDown}
                {...(onViewLineage ? { onViewLineage } : {})}
                {...(onCreateTicket ? { onCreateTicket } : {})}
              />
            );
          })}
        </ol>
      </SortableContext>
    </DndContext>
  );
}

/**
 * CarryForwardLineageView — visualization of a carry-forward provenance chain.
 */
import { cn } from "../../lib/utils.js";
import type { CarryForwardLineageResponse, CarryForwardNode } from "../../api/ticketTypes.js";
import type { CommitOutcome } from "../../api/planTypes.js";

export interface CarryForwardLineageViewProps {
  readonly lineage: CarryForwardLineageResponse;
  readonly loading?: boolean;
}

const OUTCOME_STYLES: Record<CommitOutcome, { cls: string; label: string }> = {
  ACHIEVED:           { cls: "bg-foreground/10 text-foreground font-bold",   label: "✓ Achieved" },
  PARTIALLY_ACHIEVED: { cls: "bg-neutral-200 text-neutral-600",              label: "◑ Partial" },
  NOT_ACHIEVED:       { cls: "bg-neutral-300 text-foreground underline",     label: "✗ Not achieved" },
  CANCELED:           { cls: "bg-neutral-100 text-neutral-500",              label: "— Canceled" },
};

function ChainNode({ node, isCurrent }: { readonly node: CarryForwardNode; readonly isCurrent: boolean }) {
  const outcomeMeta = node.outcome ? OUTCOME_STYLES[node.outcome] : null;

  return (
    <div
      data-testid={`cf-node-${node.commitId}`}
      className={cn(
        "rounded-default border p-3 min-w-[130px] max-w-[180px] flex flex-col gap-1 shrink-0",
        isCurrent
          ? "border-primary bg-primary text-primary-foreground"
          : "border-border bg-surface text-foreground",
      )}
    >
      <span data-testid={`cf-node-week-${node.commitId}`} className={cn("text-xs font-bold", isCurrent && "opacity-80")}>
        {node.weekStartDate}
      </span>
      <span data-testid={`cf-node-title-${node.commitId}`} className="text-xs font-semibold overflow-hidden text-ellipsis whitespace-nowrap" title={node.title}>
        {node.title}
      </span>
      {node.streak > 0 && (
        <span data-testid={`cf-node-streak-${node.commitId}`} className={cn("text-[0.65rem] rounded-full px-1.5 py-px font-semibold self-start", isCurrent ? "bg-primary-foreground/25 text-primary-foreground" : "bg-muted-bg text-muted")}>
          {node.streak}× CF
        </span>
      )}
      {outcomeMeta ? (
        <span data-testid={`cf-node-outcome-${node.commitId}`} className={cn("text-[0.65rem] rounded-full px-1.5 py-px font-semibold self-start", isCurrent ? "bg-primary-foreground/20 text-primary-foreground" : outcomeMeta.cls)}>
          {outcomeMeta.label}
        </span>
      ) : (
        <span data-testid={`cf-node-pending-${node.commitId}`} className={cn("text-[0.65rem]", isCurrent ? "text-primary-foreground/70" : "text-muted")}>
          {isCurrent ? "Current" : "Pending"}
        </span>
      )}
    </div>
  );
}

export function CarryForwardLineageView({ lineage, loading = false }: CarryForwardLineageViewProps) {
  if (loading) {
    return (
      <div data-testid="cf-lineage-loading" role="status" aria-label="Loading lineage" className="text-sm text-muted">
        Loading lineage…
      </div>
    );
  }

  if (lineage.chain.length === 0) {
    return (
      <div data-testid="cf-lineage-empty" className="py-4 text-center text-sm text-muted">
        No carry-forward history.
      </div>
    );
  }

  return (
    <section data-testid="cf-lineage-view" aria-label="Carry-forward provenance chain">
      <h4 className="m-0 mb-3 text-xs font-bold uppercase tracking-widest text-muted">
        Carry-forward Lineage
      </h4>
      <div data-testid="cf-lineage-chain" className="flex items-center overflow-x-auto pb-2">
        {lineage.chain.map((node, idx) => (
          <div key={node.commitId} className="flex items-center">
            {idx > 0 && (
              <span aria-hidden="true" className="text-muted px-1 shrink-0">→</span>
            )}
            <ChainNode node={node} isCurrent={node.commitId === lineage.currentCommitId} />
          </div>
        ))}
      </div>
      <p data-testid="cf-lineage-length" className="mt-2 text-xs text-muted">
        {lineage.chain.length} {lineage.chain.length === 1 ? "entry" : "entries"} in chain
      </p>
    </section>
  );
}

/**
 * ScopeChangeDialog — captures reason for a post-lock scope change.
 */
import { useState, type FormEvent } from "react";
import { Lock, X } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Select } from "../ui/Select.js";
import { cn } from "../../lib/utils.js";
import type { CommitResponse, ScopeChangeAction, ChessPiece, EstimatePoints } from "../../api/planTypes.js";

const REASON_OPTIONS: { value: string; label: string }[] = [
  { value: "Priority shift — more important work emerged", label: "Priority shift — more important work emerged" },
  { value: "Scope expanded — original estimate was too small", label: "Scope expanded — original estimate was too small" },
  { value: "Blocked — external dependency", label: "Blocked — external dependency" },
  { value: "Resource unavailable", label: "Resource unavailable" },
  { value: "Technical obstacle discovered", label: "Technical obstacle discovered" },
  { value: "Business context changed", label: "Business context changed" },
  { value: "Error correction — wrong commit included at lock", label: "Error correction — wrong commit included at lock" },
  { value: "Other", label: "Other" },
];

const CHESS_PIECE_LABELS: Record<ChessPiece, string> = {
  KING: "♔ King", QUEEN: "♕ Queen", ROOK: "♖ Rook", BISHOP: "♗ Bishop", KNIGHT: "♘ Knight", PAWN: "♙ Pawn",
};

interface FieldChange { readonly field: string; readonly before: string; readonly after: string; }

function computeChanges(before: CommitResponse, after: Partial<CommitResponse>): FieldChange[] {
  const changes: FieldChange[] = [];
  if (after.title !== undefined && after.title !== before.title) changes.push({ field: "Title", before: before.title, after: after.title });
  if (after.chessPiece !== undefined && after.chessPiece !== before.chessPiece) changes.push({ field: "Chess Piece", before: CHESS_PIECE_LABELS[before.chessPiece], after: CHESS_PIECE_LABELS[after.chessPiece as ChessPiece] });
  if (after.estimatePoints !== undefined && after.estimatePoints !== before.estimatePoints) changes.push({ field: "Estimate", before: before.estimatePoints != null ? `${before.estimatePoints} pts` : "—", after: `${after.estimatePoints} pts` });
  if (after.rcdoNodeId !== undefined && after.rcdoNodeId !== before.rcdoNodeId) changes.push({ field: "RCDO", before: before.rcdoNodeId ?? "—", after: (after.rcdoNodeId as string) ?? "—" });
  if (after.description !== undefined && after.description !== before.description) changes.push({ field: "Description", before: before.description ?? "—", after: (after.description as string) ?? "—" });
  return changes;
}

export interface ScopeChangeDialogProps {
  readonly action: ScopeChangeAction;
  readonly commit: CommitResponse | null;
  readonly proposedChanges?: Partial<CommitResponse>;
  readonly newCommitTitle?: string;
  readonly onConfirm: (reason: string) => void;
  readonly onCancel: () => void;
  readonly isSubmitting?: boolean;
}

const ACTION_LABELS: Record<ScopeChangeAction, string> = {
  ADD: "Add Commit (Post-lock)", REMOVE: "Remove Commit (Post-lock)", EDIT: "Edit Commit (Post-lock)",
};
const ACTION_CLS: Record<ScopeChangeAction, string> = {
  ADD: "text-success", REMOVE: "text-danger", EDIT: "text-primary",
};
const ACTION_BTN_VARIANT: Record<ScopeChangeAction, "success" | "danger" | "primary"> = {
  ADD: "success", REMOVE: "danger", EDIT: "primary",
};

const thCls = "px-2.5 py-1.5 text-left text-xs font-semibold border-b border-border";

export function ScopeChangeDialog({ action, commit, proposedChanges, newCommitTitle, onConfirm, onCancel, isSubmitting = false }: ScopeChangeDialogProps) {
  const [selectedReason, setSelectedReason] = useState("");
  const [reasonText, setReasonText] = useState("");
  const [reasonError, setReasonError] = useState<string | null>(null);

  const fieldChanges = action === "EDIT" && commit && proposedChanges ? computeChanges(commit, proposedChanges) : [];

  function handleSubmit(e: FormEvent) {
    e.preventDefault();
    const reason = selectedReason === "Other" ? reasonText.trim() : selectedReason;
    if (!reason) { setReasonError("Please select or enter a reason"); return; }
    setReasonError(null);
    onConfirm(reason);
  }

  return (
    <div role="dialog" aria-modal="true" aria-labelledby="scope-change-dialog-title" data-testid="scope-change-dialog"
      className="fixed inset-0 z-[1200] flex items-center justify-center bg-black/40 backdrop-blur-[2px]">
      <div className="w-full max-w-lg rounded-lg border border-border bg-surface p-6 shadow-xl max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="flex items-center justify-between mb-4">
          <h3 id="scope-change-dialog-title" className={cn("m-0 text-base font-semibold", ACTION_CLS[action])}>
            {ACTION_LABELS[action]}
          </h3>
          <Button variant="ghost" size="icon" onClick={onCancel} aria-label="Close" className="h-7 w-7">
            <X className="h-4 w-4" />
          </Button>
        </div>

        {/* Locked notice */}
        <div data-testid="scope-change-locked-notice" className="mb-4 flex items-center gap-2 rounded-default border border-neutral-200 bg-neutral-50 px-3 py-2.5 text-xs text-foreground">
          <Lock className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
          This plan is <strong>locked</strong>. This change will be recorded in the scope-change timeline with your reason.
        </div>

        {/* What's changing */}
        {action === "ADD" && newCommitTitle && (
          <div data-testid="scope-change-add-preview" className="mb-4 rounded-default border border-foreground/20 bg-foreground/5 px-3 py-2.5 text-sm">
            <span className="font-semibold text-foreground">+ Adding:</span> {newCommitTitle}
          </div>
        )}
        {action === "REMOVE" && commit && (
          <div data-testid="scope-change-remove-preview" className="mb-4 rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2.5 text-sm">
            <span className="font-semibold text-foreground">− Removing:</span> {commit.title}
          </div>
        )}
        {action === "EDIT" && fieldChanges.length > 0 && (
          <div data-testid="scope-change-edit-preview" className="mb-4 overflow-hidden rounded-default border border-border">
            <div className="bg-background px-3 py-2 text-xs font-semibold uppercase tracking-wider text-muted">
              Changes to: {commit?.title}
            </div>
            <table className="w-full border-collapse" aria-label="Commit field changes">
              <thead>
                <tr>
                  <th className={thCls}>Field</th>
                  <th className={cn(thCls, "text-foreground")}>Before</th>
                  <th className={cn(thCls, "text-foreground")}>After</th>
                </tr>
              </thead>
              <tbody>
                {fieldChanges.map((change) => (
                  <tr key={change.field} data-testid="scope-change-field-row">
                    <td className="px-2.5 py-1.5 text-xs font-semibold border-b border-border">{change.field}</td>
                    <td className="px-2.5 py-1.5 text-xs text-foreground bg-neutral-100 border-b border-border line-through">{change.before}</td>
                    <td className="px-2.5 py-1.5 text-xs text-foreground bg-foreground/5 border-b border-border font-semibold">{change.after}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Reason form */}
        <form onSubmit={handleSubmit} noValidate>
          <div className="mb-4">
            <Select
              label="Reason for change *"
              id="scope-change-reason-select"
              value={selectedReason}
              onChange={(e) => { setSelectedReason(e.target.value); setReasonError(null); }}
              aria-required="true"
              aria-describedby={reasonError ? "scope-reason-error" : undefined}
              data-testid="scope-change-reason-select"
              error={reasonError ?? undefined}
            >
              <option value="">— Select a reason —</option>
              {REASON_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>{opt.label}</option>
              ))}
            </Select>
          </div>

          {selectedReason === "Other" && (
            <div className="mb-4 flex flex-col gap-1.5">
              <label htmlFor="scope-change-reason-text" className="text-sm font-medium">
                Describe the reason <span aria-hidden="true" className="text-danger">*</span>
              </label>
              <textarea
                id="scope-change-reason-text"
                value={reasonText}
                onChange={(e) => setReasonText(e.target.value)}
                rows={3}
                data-testid="scope-change-reason-text"
                className="w-full rounded-default border border-border bg-surface px-3 py-1.5 text-sm resize-y focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:border-primary"
                placeholder="Please describe why this change is needed…"
              />
            </div>
          )}

          <div className="mt-5 flex items-center justify-end gap-2 pt-4 border-t border-border">
            <Button type="button" variant="secondary" onClick={onCancel} disabled={isSubmitting} data-testid="scope-change-cancel">
              Cancel
            </Button>
            <Button type="submit" variant={ACTION_BTN_VARIANT[action]} disabled={isSubmitting} data-testid="scope-change-confirm">
              {isSubmitting ? "Saving…" : "Confirm Change"}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

export type { EstimatePoints };

/**
 * ScopeChangeTimeline — chronological list of all post-lock scope changes.
 */
import { cn } from "../../lib/utils.js";
import type { ScopeChangeEventResponse, ScopeChangeCategory } from "../../api/planTypes.js";

const CATEGORY_LABELS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "Commit Added",
  COMMIT_REMOVED: "Commit Removed",
  ESTIMATE_CHANGED: "Estimate Changed",
  CHESS_PIECE_CHANGED: "Chess Piece Changed",
  RCDO_CHANGED: "RCDO Changed",
  PRIORITY_CHANGED: "Priority Changed",
};

const CATEGORY_CLS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "bg-neutral-800",
  COMMIT_REMOVED: "bg-neutral-600",
  ESTIMATE_CHANGED: "bg-neutral-500",
  CHESS_PIECE_CHANGED: "bg-neutral-500",
  RCDO_CHANGED: "bg-neutral-400",
  PRIORITY_CHANGED: "bg-neutral-700",
};

const CATEGORY_TEXT_CLS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "text-foreground font-bold",
  COMMIT_REMOVED: "text-foreground underline",
  ESTIMATE_CHANGED: "text-foreground",
  CHESS_PIECE_CHANGED: "text-foreground",
  RCDO_CHANGED: "text-muted",
  PRIORITY_CHANGED: "text-foreground",
};

const CATEGORY_ICONS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "+",
  COMMIT_REMOVED: "−",
  ESTIMATE_CHANGED: "~",
  CHESS_PIECE_CHANGED: "♟",
  RCDO_CHANGED: "◎",
  PRIORITY_CHANGED: "↕",
};

export interface ScopeChangeTimelineProps {
  readonly events: ScopeChangeEventResponse[];
}

export function ScopeChangeTimeline({ events }: ScopeChangeTimelineProps) {
  if (events.length === 0) {
    return (
      <div data-testid="scope-change-timeline-empty" className="py-3 text-center text-sm text-muted">
        No scope changes recorded.
      </div>
    );
  }

  return (
    <ol data-testid="scope-change-timeline" aria-label="Scope change timeline" className="list-none m-0 p-0 flex flex-col gap-2">
      {events.map((event) => {
        const badgeCls = CATEGORY_CLS[event.category] ?? "bg-neutral-500";
        const textCls = CATEGORY_TEXT_CLS[event.category] ?? "text-foreground";
        const icon = CATEGORY_ICONS[event.category] ?? "·";
        const label = CATEGORY_LABELS[event.category] ?? event.category;
        const ts = new Date(event.createdAt).toLocaleString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });

        return (
          <li key={event.id} data-testid={`scope-change-event-${event.id}`}
            className="flex gap-2.5 items-start rounded-default border border-border bg-surface p-2.5">
            <span className={cn("shrink-0 h-6 w-6 rounded-full flex items-center justify-center text-xs font-bold text-background", badgeCls)} aria-hidden="true">
              {icon}
            </span>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 flex-wrap">
                <span className={cn("text-xs font-semibold", textCls)}>{label}</span>
                <span className="text-xs text-muted">{ts}</span>
              </div>
              <p className="m-0 mt-1 text-xs text-muted">{event.reason}</p>
              {event.previousValue != null && event.newValue != null && (
                <div className="flex gap-1.5 mt-1 items-center text-xs flex-wrap">
                  <span className="font-mono px-1.5 py-px rounded bg-neutral-100 text-foreground line-through">{event.previousValue}</span>
                  <span className="text-muted">→</span>
                  <span className="font-mono px-1.5 py-px rounded bg-foreground/5 text-foreground font-semibold">{event.newValue}</span>
                </div>
              )}
            </div>
          </li>
        );
      })}
    </ol>
  );
}

/**
 * LockConfirmDialog — confirmation dialog before locking a plan.
 */
import { Lock } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../ui/Dialog.js";
import type { CommitResponse, ChessPiece } from "../../api/planTypes.js";

const CHESS_PIECE_ICONS: Record<ChessPiece, string> = {
  KING: "♔", QUEEN: "♕", ROOK: "♖", BISHOP: "♗", KNIGHT: "♘", PAWN: "♙",
};

export interface LockConfirmDialogProps {
  readonly commits: CommitResponse[];
  readonly capacityBudgetPoints: number;
  readonly weekLabel: string;
  readonly onConfirm: () => void;
  readonly onCancel: () => void;
  readonly isLocking?: boolean;
}

export function LockConfirmDialog({ commits, capacityBudgetPoints, weekLabel, onConfirm, onCancel, isLocking = false }: LockConfirmDialogProps) {
  const totalPoints = commits.reduce((s, c) => s + (c.estimatePoints ?? 0), 0);
  const rcdoCoverage = Math.round((commits.filter((c) => c.rcdoNodeId).length / Math.max(commits.length, 1)) * 100);
  const chessPieceCounts = commits.reduce<Record<ChessPiece, number>>((acc, c) => {
    acc[c.chessPiece] = (acc[c.chessPiece] ?? 0) + 1;
    return acc;
  }, {} as Record<ChessPiece, number>);
  const pieceOrder: ChessPiece[] = ["KING", "QUEEN", "ROOK", "BISHOP", "KNIGHT", "PAWN"];

  return (
    <Dialog open onClose={onCancel} aria-label="Lock Plan" data-testid="lock-confirm-dialog">
      <DialogHeader>
        <DialogTitle className="flex items-center gap-2">
          <Lock className="h-4 w-4 text-primary" aria-hidden="true" />
          Lock Plan
        </DialogTitle>
        <DialogDescription>{weekLabel}</DialogDescription>
      </DialogHeader>

      {/* Summary stats */}
      <div data-testid="lock-confirm-summary" className="mb-5 grid grid-cols-3 gap-3 rounded-default border border-border bg-background p-3 text-center">
        <div>
          <div data-testid="lock-confirm-commit-count" className="text-2xl font-bold text-primary">{commits.length}</div>
          <div className="text-xs text-muted">commits</div>
        </div>
        <div>
          <div data-testid="lock-confirm-total-points" className="text-2xl font-bold text-primary">{totalPoints}/{capacityBudgetPoints}</div>
          <div className="text-xs text-muted">points</div>
        </div>
        <div>
          <div data-testid="lock-confirm-rcdo-coverage" className="text-2xl font-bold text-primary">{rcdoCoverage}%</div>
          <div className="text-xs text-muted">RCDO coverage</div>
        </div>
      </div>

      {/* Chess piece breakdown */}
      <div className="mb-5">
        <p className="m-0 mb-2 text-xs font-semibold uppercase tracking-wider text-muted">Commit breakdown</p>
        <div data-testid="lock-confirm-piece-breakdown" className="flex flex-wrap gap-1.5">
          {pieceOrder.filter((p) => chessPieceCounts[p] > 0).map((piece) => (
            <span key={piece} data-testid={`piece-count-${piece.toLowerCase()}`} className="rounded-full bg-neutral-200 px-2.5 py-0.5 text-xs font-semibold text-neutral-800">
              {CHESS_PIECE_ICONS[piece]} {chessPieceCounts[piece]}×{piece.charAt(0) + piece.slice(1).toLowerCase()}
            </span>
          ))}
        </div>
      </div>

      <p className="mb-5 text-sm text-muted">
        Once locked, edits require a scope-change reason. You can start reconciliation once the week ends.
      </p>

      <DialogFooter>
        <Button variant="secondary" onClick={onCancel} disabled={isLocking} data-testid="lock-confirm-cancel">
          Cancel
        </Button>
        <Button variant="primary" onClick={onConfirm} disabled={isLocking} data-testid="lock-confirm-btn">
          <Lock className="h-3.5 w-3.5" />
          {isLocking ? "Locking…" : "Confirm Lock"}
        </Button>
      </DialogFooter>
    </Dialog>
  );
}

/**
 * Modal confirmation dialog for archiving an RCDO node.
 */
import { AlertTriangle } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Dialog, DialogHeader, DialogTitle, DialogFooter } from "../ui/Dialog.js";

interface ArchiveConfirmDialogProps {
  readonly nodeName: string;
  readonly hasActiveChildren: boolean;
  readonly onConfirm: () => void;
  readonly onCancel: () => void;
  readonly submitting: boolean;
}

export function ArchiveConfirmDialog({ nodeName, hasActiveChildren, onConfirm, onCancel, submitting }: ArchiveConfirmDialogProps) {
  return (
    <Dialog open onClose={onCancel} aria-label={`Archive ${nodeName}`}>
      <DialogHeader>
        <DialogTitle>Archive "{nodeName}"?</DialogTitle>
      </DialogHeader>

      {hasActiveChildren ? (
        <div data-testid="archive-blocked-message" className="mb-4 flex items-start gap-2 rounded-default border border-neutral-300 bg-neutral-100 p-3 text-sm text-foreground font-semibold">
          <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" aria-hidden="true" />
          <span>
            <strong>Cannot archive.</strong> This node has active child nodes.
            Archive all children first before archiving this node.
          </span>
        </div>
      ) : (
        <p className="mb-4 text-sm text-muted">
          Archiving will hide this node from active planning views. Commits already linked to this node will retain
          their linkage, but the node will no longer be selectable for new commits.
        </p>
      )}

      <DialogFooter>
        <Button variant="secondary" onClick={onCancel} disabled={submitting}>Cancel</Button>
        <Button
          variant="danger"
          onClick={onConfirm}
          disabled={hasActiveChildren || submitting}
          aria-disabled={hasActiveChildren || submitting}
          data-testid="archive-confirm-button"
        >
          {submitting ? "Archiving…" : "Archive"}
        </Button>
      </DialogFooter>
    </Dialog>
  );
}

/**
 * TicketForm — modal form for creating or editing a native ticket.
 */
import { useState, type FormEvent } from "react";
import { X, ChevronDown, ChevronUp, Check } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Input } from "../ui/Input.js";
import { Select } from "../ui/Select.js";
import { RcdoTreeView } from "../rcdo/RcdoTreeView.js";
import type { RcdoTreeNode } from "../../api/rcdoTypes.js";
import type { CreateTicketPayload, TicketStatus, TicketPriority, TicketResponse } from "../../api/ticketTypes.js";
import type { EstimatePoints } from "../../api/planTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../../api/ticketTypes.js";

const TICKET_STATUSES: TicketStatus[] = ["TODO", "IN_PROGRESS", "BLOCKED", "DONE", "CANCELED"];
const TICKET_PRIORITIES: TicketPriority[] = ["CRITICAL", "HIGH", "MEDIUM", "LOW"];
const ESTIMATE_POINTS: EstimatePoints[] = [1, 2, 3, 5, 8];

export interface TicketFormProps {
  readonly mode: "create" | "edit";
  readonly initialValues?: Partial<CreateTicketPayload>;
  readonly currentUserId: string;
  readonly currentTeamId?: string;
  /** RCDO tree for the picker. When provided, shows a browsable tree instead of a text input. */
  readonly rcdoTree?: RcdoTreeNode[];
  readonly onSubmit: (payload: CreateTicketPayload) => Promise<void>;
  readonly onCancel: () => void;
  readonly ticket?: TicketResponse;
}

function findNodeById(nodes: RcdoTreeNode[], id: string): RcdoTreeNode | null {
  for (const node of nodes) {
    if (node.id === id) return node;
    const found = findNodeById(node.children, id);
    if (found) return found;
  }
  return null;
}

const textareaCls = "w-full rounded-default border border-border bg-surface px-3 py-1.5 text-sm resize-y focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:border-primary";

export function TicketForm({ mode, initialValues, currentUserId, currentTeamId, rcdoTree, onSubmit, onCancel, ticket }: TicketFormProps) {
  const [title, setTitle] = useState(ticket?.title ?? initialValues?.title ?? "");
  const [description, setDescription] = useState(ticket?.description ?? initialValues?.description ?? "");
  const [status, setStatus] = useState<TicketStatus>(ticket?.status ?? initialValues?.status ?? "TODO");
  const [priority, setPriority] = useState<TicketPriority>(ticket?.priority ?? initialValues?.priority ?? "MEDIUM");
  const [assignee, setAssignee] = useState(ticket?.assigneeUserId ?? initialValues?.assigneeUserId ?? "");
  const [reporter, setReporter] = useState(ticket?.reporterUserId ?? initialValues?.reporterUserId ?? currentUserId);
  const [teamId, setTeamId] = useState(ticket?.teamId ?? initialValues?.teamId ?? currentTeamId ?? "");
  const [estimatePoints, setEstimatePoints] = useState<EstimatePoints | "">(ticket?.estimatePoints ?? initialValues?.estimatePoints ?? "");
  const [rcdoNodeId, setRcdoNodeId] = useState(ticket?.rcdoNodeId ?? initialValues?.rcdoNodeId ?? "");
  const [targetWeek, setTargetWeek] = useState(ticket?.targetWeekStartDate ?? initialValues?.targetWeekStartDate ?? "");
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [showRcdoPicker, setShowRcdoPicker] = useState(false);

  const hasRcdoTree = rcdoTree && rcdoTree.length > 0;
  const selectedRcdoNode = hasRcdoTree && rcdoNodeId ? findNodeById(rcdoTree, rcdoNodeId) : null;

  function validate(): boolean {
    const next: Record<string, string> = {};
    if (!title.trim()) next.title = "Title is required.";
    if (!teamId.trim()) next.teamId = "Team is required.";
    if (!reporter.trim()) next.reporter = "Reporter is required.";
    setErrors(next);
    return Object.keys(next).length === 0;
  }

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!validate()) return;
    setSaving(true); setSubmitError(null);
    try {
      await onSubmit({
        title: title.trim(),
        ...(description.trim() ? { description: description.trim() } : {}),
        status, priority,
        ...(assignee.trim() ? { assigneeUserId: assignee.trim() } : {}),
        reporterUserId: reporter.trim(), teamId: teamId.trim(),
        ...(rcdoNodeId.trim() ? { rcdoNodeId: rcdoNodeId.trim() } : {}),
        ...(estimatePoints !== "" ? { estimatePoints: estimatePoints as EstimatePoints } : {}),
        ...(targetWeek ? { targetWeekStartDate: targetWeek } : {}),
      });
    } catch (err) {
      setSubmitError(err instanceof Error ? err.message : "Failed to save ticket.");
    } finally {
      setSaving(false);
    }
  }

  return (
    <div role="dialog" aria-modal="true" aria-label={mode === "create" ? "Create ticket" : "Edit ticket"} data-testid="ticket-form-dialog"
      className="fixed inset-0 z-[1100] flex items-center justify-center bg-black/35 overflow-auto p-4">
      <div className="w-full max-w-[520px] rounded-lg border border-border bg-surface p-6 shadow-xl max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between mb-5">
          <h3 className="m-0 text-base font-semibold">{mode === "create" ? "Create Ticket" : "Edit Ticket"}</h3>
          <Button variant="ghost" size="icon" type="button" onClick={onCancel} aria-label="Close" className="h-7 w-7">
            <X className="h-4 w-4" />
          </Button>
        </div>

        <form onSubmit={(e) => void handleSubmit(e)} noValidate className="flex flex-col gap-3.5">
          {/* Title */}
          <Input id="tf-title" label="Title *" type="text" value={title} onChange={(e) => setTitle(e.target.value)} data-testid="ticket-form-title" placeholder="Short descriptive title" required error={errors.title} errorTestId="ticket-form-title-error" />

          {/* Description */}
          <div className="flex flex-col gap-1.5">
            <label htmlFor="tf-desc" className="text-sm font-medium">Description</label>
            <textarea id="tf-desc" value={description} onChange={(e) => setDescription(e.target.value)} data-testid="ticket-form-description" className={textareaCls} placeholder="Optional details…" style={{ minHeight: "80px" }} />
          </div>

          {/* Status + Priority row */}
          <div className="flex gap-3 flex-wrap">
            <div className="flex-1 min-w-[120px]">
              <Select id="tf-status" label="Status" value={status} onChange={(e) => setStatus(e.target.value as TicketStatus)} data-testid="ticket-form-status">
                {TICKET_STATUSES.map((s) => <option key={s} value={s}>{TICKET_STATUS_LABELS[s]}</option>)}
              </Select>
            </div>
            <div className="flex-1 min-w-[120px]">
              <Select id="tf-priority" label="Priority *" value={priority} onChange={(e) => setPriority(e.target.value as TicketPriority)} data-testid="ticket-form-priority">
                {TICKET_PRIORITIES.map((p) => <option key={p} value={p}>{TICKET_PRIORITY_LABELS[p]}</option>)}
              </Select>
            </div>
          </div>

          <Input id="tf-assignee" label="Assignee (User ID)" type="text" value={assignee} onChange={(e) => setAssignee(e.target.value)} data-testid="ticket-form-assignee" placeholder="Leave blank to leave unassigned" />
          <Input id="tf-reporter" label="Reporter *" type="text" value={reporter} onChange={(e) => setReporter(e.target.value)} data-testid="ticket-form-reporter" error={errors.reporter} />
          <Input id="tf-team" label="Team *" type="text" value={teamId} onChange={(e) => setTeamId(e.target.value)} data-testid="ticket-form-team" placeholder="Team ID" error={errors.teamId} errorTestId="ticket-form-team-error" />

          <div>
            <Select id="tf-points" label="Estimate Points (optional)" value={String(estimatePoints)} onChange={(e) => setEstimatePoints(e.target.value === "" ? "" : (Number(e.target.value) as EstimatePoints))} data-testid="ticket-form-estimate">
              <option value="">Unestimated</option>
              {ESTIMATE_POINTS.map((p) => <option key={p} value={p}>{p} {p === 1 ? "pt" : "pts"}</option>)}
            </Select>
          </div>

          {/* RCDO picker */}
          <div>
            <p className="text-sm font-medium mb-1.5">RCDO Link (optional)</p>
            {selectedRcdoNode && (
              <div data-testid="ticket-rcdo-selected" className="flex items-center gap-2 px-3 py-2 rounded-default border border-foreground/20 bg-foreground/5 mb-2 text-sm">
                <Check className="h-3.5 w-3.5 text-foreground shrink-0" aria-hidden="true" />
                <span className="flex-1 text-foreground">{selectedRcdoNode.title}</span>
                <Button variant="ghost" size="icon" type="button" onClick={() => setRcdoNodeId("")} aria-label="Clear RCDO link" className="h-6 w-6 text-muted">
                  <X className="h-3 w-3" />
                </Button>
              </div>
            )}
            {hasRcdoTree ? (
              <>
                <Button variant="secondary" size="sm" type="button" onClick={() => setShowRcdoPicker((v) => !v)} data-testid="ticket-rcdo-picker-toggle" aria-expanded={showRcdoPicker}>
                  {showRcdoPicker ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />}
                  {showRcdoPicker ? "Close RCDO picker" : "Browse RCDO nodes"}
                </Button>
                {showRcdoPicker && (
                  <div data-testid="ticket-rcdo-picker-panel" className="mt-2 rounded-default border border-border p-3 max-h-[250px] overflow-y-auto">
                    <RcdoTreeView
                      nodes={rcdoTree}
                      selectedId={rcdoNodeId || null}
                      onSelect={(id) => { setRcdoNodeId(id); setShowRcdoPicker(false); }}
                      statusFilter="active-only"
                      searchQuery=""
                    />
                  </div>
                )}
              </>
            ) : (
              <Input id="tf-rcdo" type="text" value={rcdoNodeId} onChange={(e) => setRcdoNodeId(e.target.value)} data-testid="ticket-form-rcdo" placeholder="RCDO node ID" />
            )}
          </div>
          <Input id="tf-target-week" label="Target Week (optional)" type="date" value={targetWeek} onChange={(e) => setTargetWeek(e.target.value)} data-testid="ticket-form-target-week" />

          {submitError && (
            <div role="alert" data-testid="ticket-form-submit-error" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2 text-xs text-foreground font-semibold">{submitError}</div>
          )}

          <div className="flex gap-2 justify-end mt-1">
            <Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button>
            <Button type="submit" variant="primary" disabled={saving} data-testid="ticket-form-submit">
              {saving ? (mode === "create" ? "Creating…" : "Saving…") : (mode === "create" ? "Create Ticket" : "Save Changes")}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

/**
 * TicketDetailView — full ticket detail panel.
 */
import { useState, useCallback } from "react";
import { X, Pencil } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import type { TicketResponse, TicketStatus, TicketStatusHistory, LinkedCommitEntry } from "../../api/ticketTypes.js";
import type { TeamMember } from "../../api/teamTypes.js";
import type { CommitOutcome } from "../../api/planTypes.js";
import { TICKET_STATUS_LABELS, TICKET_STATUS_TRANSITIONS, TICKET_PRIORITY_LABELS } from "../../api/ticketTypes.js";

export interface TicketDetailViewProps {
  readonly ticket: TicketResponse;
  readonly onStatusTransition: (ticketId: string, newStatus: TicketStatus) => Promise<void>;
  readonly onAssigneeChange: (ticketId: string, assigneeUserId: string) => Promise<void>;
  /** Team members for the assignee dropdown. Falls back to text input when empty/undefined. */
  readonly teamMembers?: readonly TeamMember[];
  readonly rcdoPath?: string;
  readonly onClose?: () => void;
  readonly onEdit?: () => void;
}

const STATUS_BADGE_VARIANT: Record<TicketStatus, "default" | "primary" | "success" | "danger"> = {
  TODO: "default", IN_PROGRESS: "primary", DONE: "success", CANCELED: "default", BLOCKED: "danger",
};

const OUTCOME_LABELS: Record<CommitOutcome, string> = {
  ACHIEVED: "✓ Achieved", PARTIALLY_ACHIEVED: "◑ Partial", NOT_ACHIEVED: "✗ Not achieved", CANCELED: "— Canceled",
};
const OUTCOME_CLS: Record<CommitOutcome, string> = {
  ACHIEVED: "text-success", PARTIALLY_ACHIEVED: "text-warning", NOT_ACHIEVED: "text-danger", CANCELED: "text-muted",
};

const shCls = "text-[0.75rem] font-bold uppercase tracking-wider text-muted m-0 mb-2";
const metaRowCls = "flex gap-2 text-sm items-baseline";
const metaLabelCls = "font-semibold min-w-[100px] shrink-0 text-muted";

function StatusHistoryTimeline({ history }: { history: TicketStatusHistory[] }) {
  if (history.length === 0) {
    return <p data-testid="status-history-empty" className="text-sm text-muted">No status changes recorded.</p>;
  }
  return (
    <ol data-testid="status-history-timeline" className="list-none m-0 p-0 flex flex-col gap-2">
      {[...history].reverse().map((entry) => (
        <li key={entry.id} data-testid={`history-entry-${entry.id}`} className="flex items-start gap-2.5 text-xs">
          <span className="mt-1 h-2 w-2 rounded-full bg-primary shrink-0" />
          <div>
            <span className="text-muted">{new Date(entry.changedAt).toLocaleString()}</span>
            {" — "}
            {entry.fromStatus ? <><strong>{TICKET_STATUS_LABELS[entry.fromStatus]}</strong>{" → "}</> : null}
            <strong>{TICKET_STATUS_LABELS[entry.toStatus]}</strong>
            {entry.note && <span className="text-muted"> ({entry.note})</span>}
          </div>
        </li>
      ))}
    </ol>
  );
}

function LinkedCommitsList({ commits }: { commits: LinkedCommitEntry[] }) {
  if (commits.length === 0) {
    return <p data-testid="linked-commits-empty" className="text-sm text-muted">No linked commits.</p>;
  }
  return (
    <ul data-testid="linked-commits-list" className="list-none m-0 p-0 flex flex-col gap-1.5">
      {commits.map((c) => (
        <li key={c.commitId} data-testid={`linked-commit-${c.commitId}`}
          className="rounded-default border border-border bg-background px-3 py-2 text-sm flex justify-between items-center flex-wrap gap-1.5">
          <div>
            <span className="font-semibold">{c.commitTitle}</span>
            <span className="ml-2 text-xs text-muted">{c.weekStartDate} · {c.chessPiece}{c.estimatePoints != null ? ` · ${c.estimatePoints}pts` : ""}</span>
          </div>
          {c.outcome && (
            <span data-testid={`linked-commit-outcome-${c.commitId}`} className={cn("text-xs font-semibold", OUTCOME_CLS[c.outcome])}>
              {OUTCOME_LABELS[c.outcome]}
            </span>
          )}
        </li>
      ))}
    </ul>
  );
}

export function TicketDetailView({ ticket, onStatusTransition, onAssigneeChange, teamMembers, rcdoPath, onClose, onEdit }: TicketDetailViewProps) {
  const [transitioning, setTransitioning] = useState<TicketStatus | null>(null);
  const [transitionError, setTransitionError] = useState<string | null>(null);
  const [assigneeInput, setAssigneeInput] = useState(ticket.assigneeUserId ?? "");
  const [assigneeSaving, setAssigneeSaving] = useState(false);
  const [assigneeError, setAssigneeError] = useState<string | null>(null);

  const nextStatuses = TICKET_STATUS_TRANSITIONS[ticket.status];

  const handleTransition = useCallback(async (newStatus: TicketStatus) => {
    setTransitioning(newStatus); setTransitionError(null);
    try { await onStatusTransition(ticket.id, newStatus); }
    catch (err) { setTransitionError(err instanceof Error ? err.message : "Status transition failed."); }
    finally { setTransitioning(null); }
  }, [ticket.id, onStatusTransition]);

  const handleAssigneeChange = useCallback(async () => {
    setAssigneeSaving(true); setAssigneeError(null);
    try { await onAssigneeChange(ticket.id, assigneeInput.trim()); }
    catch (err) { setAssigneeError(err instanceof Error ? err.message : "Assignment change failed."); }
    finally { setAssigneeSaving(false); }
  }, [ticket.id, assigneeInput, onAssigneeChange]);

  return (
    <div data-testid="ticket-detail-view" className="rounded-default border border-border bg-surface flex flex-col gap-0 overflow-hidden">
      {/* Header */}
      <div className="px-5 py-4 border-b border-border flex items-start justify-between gap-4 flex-wrap">
        <div className="flex flex-col gap-1.5 flex-1">
          <div className="flex items-center gap-2 flex-wrap">
            <span data-testid="ticket-detail-key" className="font-mono text-xs font-bold text-muted">{ticket.key}</span>
            <Badge variant={STATUS_BADGE_VARIANT[ticket.status]} data-testid="ticket-detail-status-badge">
              {TICKET_STATUS_LABELS[ticket.status]}
            </Badge>
          </div>
          <h2 data-testid="ticket-detail-title" className="m-0 text-lg font-bold">{ticket.title}</h2>
        </div>
        <div className="flex gap-2 shrink-0">
          {onEdit && (
            <Button variant="secondary" size="sm" onClick={onEdit} data-testid="ticket-detail-edit-btn">
              <Pencil className="h-3 w-3" />Edit
            </Button>
          )}
          {onClose && (
            <Button variant="ghost" size="icon" onClick={onClose} aria-label="Close ticket detail" data-testid="ticket-detail-close-btn" className="h-8 w-8">
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>

      <div className="px-5 py-4 flex flex-col gap-5">
        {/* Status transitions */}
        {nextStatuses.length > 0 && (
          <div>
            <p className={shCls}>Status Transitions</p>
            <div data-testid="status-transition-buttons" className="flex gap-1.5 flex-wrap">
              {nextStatuses.map((next) => (
                <button key={next} type="button" onClick={() => void handleTransition(next)} disabled={transitioning !== null} data-testid={`transition-btn-${next.toLowerCase()}`}
                  className={cn(
                    "px-3.5 py-1.5 rounded-full border text-xs font-semibold transition-opacity",
                    transitioning !== null && "cursor-not-allowed opacity-60",
                    next === "DONE" ? "border-foreground/30 bg-foreground/5 text-foreground font-bold" :
                    next === "BLOCKED" ? "border-neutral-300 bg-neutral-100 text-foreground" :
                    next === "CANCELED" ? "border-neutral-200 bg-neutral-100 text-neutral-600" :
                    "border-border bg-background text-foreground",
                  )}>
                  {transitioning === next ? "…" : `→ ${TICKET_STATUS_LABELS[next]}`}
                </button>
              ))}
            </div>
            {transitionError && <span data-testid="transition-error" role="alert" className="mt-1 block text-xs text-danger">{transitionError}</span>}
          </div>
        )}

        {ticket.description && (
          <div>
            <p className={shCls}>Description</p>
            <p data-testid="ticket-detail-description" className="m-0 text-sm leading-relaxed">{ticket.description}</p>
          </div>
        )}

        <div>
          <p className={shCls}>Details</p>
          <div data-testid="ticket-detail-meta" className="flex flex-col gap-1.5">
            <div className={metaRowCls}><span className={metaLabelCls}>Priority</span><span data-testid="ticket-detail-priority">{TICKET_PRIORITY_LABELS[ticket.priority]}</span></div>
            <div className={metaRowCls}><span className={metaLabelCls}>Reporter</span><span data-testid="ticket-detail-reporter">{ticket.reporterDisplayName ?? ticket.reporterUserId}</span></div>
            <div className={metaRowCls}><span className={metaLabelCls}>Team</span><span data-testid="ticket-detail-team">{ticket.teamName ?? ticket.teamId}</span></div>
            {ticket.rcdoNodeId && <div className={metaRowCls}><span className={metaLabelCls}>RCDO</span><span data-testid="ticket-detail-rcdo">{rcdoPath ?? ticket.rcdoNodeId}</span></div>}
            {ticket.estimatePoints != null && <div className={metaRowCls}><span className={metaLabelCls}>Estimate</span><span data-testid="ticket-detail-estimate">{ticket.estimatePoints} pts</span></div>}
            {ticket.targetWeekStartDate && <div className={metaRowCls}><span className={metaLabelCls}>Target Week</span><span data-testid="ticket-detail-target-week">{ticket.targetWeekStartDate}</span></div>}
            <div className={metaRowCls}><span className={metaLabelCls}>Created</span><span>{new Date(ticket.createdAt).toLocaleString()}</span></div>
          </div>
        </div>

        <div>
          <p className={shCls}>Assignment</p>
          <div data-testid="ticket-assignment-section" className="flex gap-2 items-center flex-wrap">
            {teamMembers && teamMembers.length > 0 ? (
              <select
                value={assigneeInput}
                onChange={(e) => setAssigneeInput(e.target.value)}
                data-testid="ticket-assignee-input"
                className="h-9 rounded-default border border-border bg-surface px-3 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 min-w-[220px]"
              >
                <option value="">Unassigned</option>
                {teamMembers.map((m) => (
                  <option key={m.id} value={m.id}>{m.displayName}</option>
                ))}
              </select>
            ) : (
              <input type="text" value={assigneeInput} onChange={(e) => setAssigneeInput(e.target.value)} placeholder="User ID (leave blank to unassign)" data-testid="ticket-assignee-input"
                className="h-9 rounded-default border border-border bg-surface px-3 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 min-w-[180px]" />
            )}
            <Button variant="primary" size="sm" onClick={() => void handleAssigneeChange()} disabled={assigneeSaving} data-testid="ticket-assign-save-btn">
              {assigneeSaving ? "Saving…" : "Update"}
            </Button>
          </div>
          {assigneeError && <span data-testid="assignee-error" role="alert" className="mt-1 block text-xs text-danger">{assigneeError}</span>}
        </div>

        <div>
          <p className={shCls}>Status History</p>
          <StatusHistoryTimeline history={ticket.statusHistory} />
        </div>

        <div>
          <p className={shCls}>Linked Commits</p>
          <LinkedCommitsList commits={ticket.linkedCommits} />
        </div>
      </div>
    </div>
  );
}

/**
 * CommitDraftAssistButton — "✨ AI Suggest" button that calls the existing
 * CommitDraftAssistService backend and renders inline suggestions.
 *
 * SOTA note: Completes the wiring of an existing backend capability to the
 * frontend (ai-eval-roadmap Phase 3a). Every suggestion shows rationale and
 * is accept/dismiss-able per PRD §17 ("assistive, not authoritarian").
 */
import { useState, useCallback } from "react";
import { Sparkles, Check, Loader2 } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import type { CommitDraftAssistResponse } from "../../api/aiApi.js";

interface CommitDraftAssistButtonProps {
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
  onAcceptTitle?: ((title: string) => void) | undefined;
  onAcceptDescription?: ((description: string) => void) | undefined;
  onAcceptSuccessCriteria?: ((criteria: string) => void) | undefined;
  onAcceptEstimatePoints?: ((points: number) => void) | undefined;
  onAcceptChessPiece?: ((piece: string) => void) | undefined;
  className?: string | undefined;
}

interface SuggestionField {
  label: string;
  current: string;
  suggested: string;
  onAccept: () => void;
}

export function CommitDraftAssistButton({
  planId,
  commitId,
  currentTitle,
  currentDescription,
  currentSuccessCriteria,
  currentEstimatePoints,
  chessPiece,
  onAcceptTitle,
  onAcceptDescription,
  onAcceptSuccessCriteria,
  onAcceptEstimatePoints,
  onAcceptChessPiece,
  className,
}: CommitDraftAssistButtonProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CommitDraftAssistResponse | null>(null);
  const [accepted, setAccepted] = useState<Set<string>>(new Set());
  const [error, setError] = useState<string | null>(null);

  const isAvailable = aiStatus?.available ?? false;

  const handleRequest = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    setAccepted(new Set());
    try {
      const response = await aiApi.commitDraftAssist({
        userId,
        planId,
        commitId,
        currentTitle,
        currentDescription,
        currentSuccessCriteria,
        currentEstimatePoints,
        chessPiece,
      });
      if (!response.aiAvailable) {
        setError("AI is currently unavailable. Try again later.");
        return;
      }
      setResult(response);
    } catch {
      setError("Failed to get AI suggestions.");
    } finally {
      setLoading(false);
    }
  }, [
    aiApi, userId, planId, commitId, currentTitle,
    currentDescription, currentSuccessCriteria, currentEstimatePoints, chessPiece,
  ]);

  const handleAccept = useCallback((field: string, acceptFn: () => void) => {
    acceptFn();
    setAccepted((prev) => new Set(prev).add(field));
  }, []);

  // Build suggestion fields from the response
  const suggestions: SuggestionField[] = [];
  if (result) {
    if (result.suggestedTitle && onAcceptTitle) {
      suggestions.push({
        label: "Title",
        current: currentTitle,
        suggested: result.suggestedTitle,
        onAccept: () => onAcceptTitle(result.suggestedTitle!),
      });
    }
    if (result.suggestedDescription && onAcceptDescription) {
      suggestions.push({
        label: "Description",
        current: currentDescription ?? "",
        suggested: result.suggestedDescription,
        onAccept: () => onAcceptDescription(result.suggestedDescription!),
      });
    }
    if (result.suggestedSuccessCriteria && onAcceptSuccessCriteria) {
      suggestions.push({
        label: "Success Criteria",
        current: currentSuccessCriteria ?? "",
        suggested: result.suggestedSuccessCriteria,
        onAccept: () => onAcceptSuccessCriteria(result.suggestedSuccessCriteria!),
      });
    }
    if (result.suggestedEstimatePoints != null && onAcceptEstimatePoints) {
      suggestions.push({
        label: "Estimate",
        current: currentEstimatePoints != null ? `${currentEstimatePoints} pts` : "not set",
        suggested: `${result.suggestedEstimatePoints} pts`,
        onAccept: () => onAcceptEstimatePoints(result.suggestedEstimatePoints!),
      });
    }
    if (result.suggestedChessPiece && onAcceptChessPiece) {
      suggestions.push({
        label: "Chess Piece",
        current: chessPiece ?? "not set",
        suggested: result.suggestedChessPiece,
        onAccept: () => onAcceptChessPiece(result.suggestedChessPiece!),
      });
    }
  }

  const allGood = result && suggestions.length === 0;

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      {/* Trigger button */}
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={() => void handleRequest()}
        disabled={loading || !isAvailable || !currentTitle.trim()}
        data-testid="ai-draft-assist-btn"
        className="self-start text-primary hover:text-primary/80"
        title={!isAvailable ? "AI unavailable" : "Get AI suggestions for this commit"}
      >
        {loading ? (
          <Loader2 className="h-3.5 w-3.5 animate-spin mr-1" />
        ) : (
          <Sparkles className="h-3.5 w-3.5 mr-1" />
        )}
        {loading ? "Thinking…" : "AI Suggest"}
      </Button>

      {/* Error */}
      {error && (
        <p className="text-xs text-danger" data-testid="ai-draft-assist-error">{error}</p>
      )}

      {/* All good */}
      {allGood && (
        <div
          className="flex items-center gap-1.5 text-xs text-foreground bg-foreground/5 rounded-default px-2.5 py-1.5"
          data-testid="ai-draft-assist-good"
        >
          <Check className="h-3.5 w-3.5" />
          Looks good! No suggestions.
          {result.suggestionId && (
            <AiFeedbackButtons suggestionId={result.suggestionId} className="ml-auto" />
          )}
        </div>
      )}

      {/* Suggestions */}
      {suggestions.length > 0 && (
        <div
          className="rounded-default border border-primary/20 bg-primary/5 p-3 flex flex-col gap-2.5"
          data-testid="ai-draft-assist-suggestions"
        >
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-primary flex items-center gap-1">
              <Sparkles className="h-3 w-3" /> AI Suggestions
            </span>
            {result?.suggestionId && (
              <AiFeedbackButtons suggestionId={result.suggestionId} />
            )}
          </div>

          {suggestions.map((s) => {
            const isAccepted = accepted.has(s.label);
            return (
              <div
                key={s.label}
                className={cn(
                  "rounded-sm border px-2.5 py-2 text-xs",
                  isAccepted
                    ? "border-foreground/20 bg-foreground/5"
                    : "border-neutral-200 bg-white",
                )}
                data-testid={`ai-suggestion-${s.label.toLowerCase().replace(/\s/g, "-")}`}
              >
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1">
                    <Badge variant="default" className="mb-1 text-[0.6rem]">
                      {s.label}
                    </Badge>
                    {s.current && (
                      <p className="m-0 text-muted line-through">{s.current}</p>
                    )}
                    <p className="m-0 font-medium text-foreground">{s.suggested}</p>
                  </div>
                  {!isAccepted && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => handleAccept(s.label, s.onAccept)}
                      className="h-6 w-6 text-foreground hover:bg-neutral-100 shrink-0"
                      aria-label={`Accept ${s.label} suggestion`}
                      data-testid={`ai-accept-${s.label.toLowerCase().replace(/\s/g, "-")}`}
                    >
                      <Check className="h-3.5 w-3.5" />
                    </Button>
                  )}
                  {isAccepted && (
                    <span className="text-[0.6rem] text-foreground font-semibold">✓ Applied</span>
                  )}
                </div>
              </div>
            );
          })}

          {result?.rationale && (
            <p className="m-0 text-[0.65rem] text-muted italic" data-testid="ai-draft-assist-rationale">
              {result.rationale}
            </p>
          )}
        </div>
      )}
    </div>
  );
}

/**
 * RcdoSuggestionInline — shows an AI-suggested RCDO link below the RCDO picker
 * in CommitForm. Fires the existing `/api/ai/rcdo-suggest` endpoint when the
 * user has typed enough title text, and presents the suggestion with rationale
 * + confidence + accept/dismiss controls.
 *
 * PRD §17: assistive, visible rationale, auditable, never auto-links.
 */
import { useState, useEffect, useRef, useCallback } from "react";
import { Check, X, Loader2 } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { AiSuggestedBadge } from "./AiSuggestedBadge.js";
import type { RcdoSuggestResponse } from "../../api/aiApi.js";

interface RcdoSuggestionInlineProps {
  planId: string;
  /** Current commit title — used for semantic matching. */
  currentTitle: string;
  /** Current commit description (optional extra context). */
  currentDescription?: string | undefined;
  /** Current chess piece (optional extra context). */
  chessPiece?: string | undefined;
  /** Currently selected RCDO node id (skip suggestion if already set). */
  currentRcdoNodeId: string;
  /** Called when user accepts the suggestion. */
  onAccept: (rcdoNodeId: string) => void;
  className?: string | undefined;
}

const MIN_TITLE_LENGTH = 8;
const DEBOUNCE_MS = 1200;

export function RcdoSuggestionInline({
  planId,
  currentTitle,
  currentDescription,
  chessPiece,
  currentRcdoNodeId,
  onAccept,
  className,
}: RcdoSuggestionInlineProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();

  const [result, setResult] = useState<RcdoSuggestResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [dismissed, setDismissed] = useState(false);
  const [accepted, setAccepted] = useState(false);

  const isAvailable = aiStatus?.available ?? false;

  // Debounce timer ref
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  // Track what we last fetched for to avoid duplicate requests
  const lastFetchedRef = useRef<string>("");

  // Reset dismissed/accepted state when the title meaningfully changes
  const titleKeyRef = useRef(currentTitle);
  useEffect(() => {
    if (currentTitle !== titleKeyRef.current) {
      titleKeyRef.current = currentTitle;
      setDismissed(false);
      setAccepted(false);
    }
  }, [currentTitle]);

  // Debounced fetch
  useEffect(() => {
    // Don't suggest if AI unavailable, title too short, user already picked an RCDO,
    // or we've been dismissed
    if (
      !isAvailable ||
      currentTitle.trim().length < MIN_TITLE_LENGTH ||
      currentRcdoNodeId ||
      dismissed
    ) {
      return;
    }

    const key = `${currentTitle.trim()}|${chessPiece ?? ""}`;
    if (key === lastFetchedRef.current) return;

    if (timerRef.current) clearTimeout(timerRef.current);

