/**
 * Expandable tree view of the full RCDO hierarchy.
 */
import { useState, useCallback, type ReactNode } from "react";
import { ChevronRight, ChevronDown } from "lucide-react";
import { Badge } from "../ui/Badge.js";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import type { RcdoTreeNode, RcdoNodeType, RcdoNodeStatus } from "../../api/rcdoTypes.js";

export type StatusFilter = "all" | "active-only" | "archived-only";

/* ── Minimal geometric SVG icons for RCDO node types ──────────────── */

/** Diamond — Rally Cry (top-level strategic anchor) */
function DiamondIcon({ className }: { readonly className?: string }) {
  return (
    <svg className={className} width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="currentColor" strokeWidth="1.5" aria-hidden="true">
      <path d="M7 1 L13 7 L7 13 L1 7 Z" />
    </svg>
  );
}

/** Triangle — Defining Objective (directional, points upward) */
function TriangleIcon({ className }: { readonly className?: string }) {
  return (
    <svg className={className} width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="currentColor" strokeWidth="1.5" aria-hidden="true">
      <path d="M7 1.5 L12.5 12 L1.5 12 Z" />
    </svg>
  );
}

/** Circle — Outcome (completion, target) */
function CircleIcon({ className }: { readonly className?: string }) {
  return (
    <svg className={className} width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="currentColor" strokeWidth="1.5" aria-hidden="true">
      <circle cx="7" cy="7" r="5.5" />
    </svg>
  );
}

const NODE_TYPE_ICON_ELEMENTS: Record<RcdoNodeType, ReactNode> = {
  RALLY_CRY: <DiamondIcon className="h-3.5 w-3.5 text-muted inline-block shrink-0" />,
  DEFINING_OBJECTIVE: <TriangleIcon className="h-3.5 w-3.5 text-muted inline-block shrink-0" />,
  OUTCOME: <CircleIcon className="h-3.5 w-3.5 text-muted inline-block shrink-0" />,
};
const NODE_TYPE_LABELS: Record<RcdoNodeType, string> = {
  RALLY_CRY: "Rally Cry",
  DEFINING_OBJECTIVE: "Defining Objective",
  OUTCOME: "Outcome",
};

const STATUS_VARIANT: Record<RcdoNodeStatus, "draft" | "success" | "default"> = {
  DRAFT: "draft",
  ACTIVE: "success",
  ARCHIVED: "default",
};

function getAllIds(nodes: RcdoTreeNode[]): Set<string> {
  const ids = new Set<string>();
  function collect(node: RcdoTreeNode) { ids.add(node.id); node.children.forEach(collect); }
  nodes.forEach(collect);
  return ids;
}

function filterTree(nodes: RcdoTreeNode[], filter: StatusFilter, searchLower: string): RcdoTreeNode[] {
  function filterNode(node: RcdoTreeNode): RcdoTreeNode | null {
    const filteredChildren = node.children.map(filterNode).filter((n): n is RcdoTreeNode => n !== null);
    const passesStatus = filter === "all" || (filter === "active-only" && node.status !== "ARCHIVED") || (filter === "archived-only" && node.status === "ARCHIVED");
    const passesSearch = !searchLower || node.title.toLowerCase().includes(searchLower);
    if ((passesStatus && passesSearch) || filteredChildren.length > 0) return { ...node, children: filteredChildren };
    return null;
  }
  return nodes.map(filterNode).filter((n): n is RcdoTreeNode => n !== null);
}

interface TreeNodeItemProps {
  readonly node: RcdoTreeNode;
  readonly depth: number;
  readonly selectedId: string | null;
  readonly expandedIds: Set<string>;
  readonly onSelect: (id: string) => void;
  readonly onToggleExpand: (id: string) => void;
}

function TreeNodeItem({ node, depth, selectedId, expandedIds, onSelect, onToggleExpand }: TreeNodeItemProps) {
  const isExpanded = expandedIds.has(node.id);
  const isSelected = selectedId === node.id;
  const hasChildren = node.children.length > 0;

  return (
    <li role="treeitem" aria-expanded={hasChildren ? isExpanded : undefined} aria-selected={isSelected} className="list-none m-0 p-0">
      <div
        className={cn(
          "flex items-center gap-1.5 px-2 py-1.5 rounded-default cursor-pointer select-none transition-colors",
          isSelected ? "bg-primary text-primary-foreground" : "hover:bg-muted/10 text-foreground",
        )}
        style={{ paddingLeft: `${depth * 1.25 + 0.5}rem` }}
        onClick={() => onSelect(node.id)}
        data-testid={`tree-node-${node.id}`}
      >
        <button
          type="button"
          aria-label={hasChildren ? (isExpanded ? `Collapse ${node.title}` : `Expand ${node.title}`) : undefined}
          onClick={(e) => { e.stopPropagation(); if (hasChildren) onToggleExpand(node.id); }}
          tabIndex={-1}
          className={cn("bg-transparent border-none cursor-pointer p-0 text-inherit flex items-center shrink-0", !hasChildren && "invisible")}
          aria-hidden={!hasChildren}
        >
          {isExpanded ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
        </button>
        <span aria-label={NODE_TYPE_LABELS[node.nodeType]} title={NODE_TYPE_LABELS[node.nodeType]} className="shrink-0">
          {NODE_TYPE_ICON_ELEMENTS[node.nodeType]}
        </span>
        <span className="flex-1 overflow-hidden text-ellipsis whitespace-nowrap text-sm font-mono">{node.title}</span>
        <Badge
          variant={STATUS_VARIANT[node.status]}
          data-testid={`status-badge-${node.status.toLowerCase()}`}
          className={cn(isSelected && "bg-primary-foreground/20 text-primary-foreground")}
        >
          {node.status.charAt(0) + node.status.slice(1).toLowerCase()}
        </Badge>
      </div>
      {hasChildren && isExpanded && (
        <ul role="group" className="m-0 p-0 list-none">
          {node.children.map((child) => (
            <TreeNodeItem key={child.id} node={child} depth={depth + 1} selectedId={selectedId} expandedIds={expandedIds} onSelect={onSelect} onToggleExpand={onToggleExpand} />
          ))}
        </ul>
      )}
    </li>
  );
}

export interface RcdoTreeViewProps {
  readonly nodes: RcdoTreeNode[];
  readonly selectedId: string | null;
  readonly onSelect: (id: string) => void;
  readonly statusFilter: StatusFilter;
  readonly searchQuery: string;
}

export function RcdoTreeView({ nodes, selectedId, onSelect, statusFilter, searchQuery }: RcdoTreeViewProps) {
  const [expandedIds, setExpandedIds] = useState<Set<string>>(() => {
    const initial = new Set<string>();
    nodes.forEach((n) => { if (n.nodeType === "RALLY_CRY") initial.add(n.id); });
    return initial;
  });

  const toggleExpand = useCallback((id: string) => {
    setExpandedIds((prev) => { const next = new Set(prev); if (next.has(id)) { next.delete(id); } else { next.add(id); } return next; });
  }, []);

  const expandAll = useCallback(() => setExpandedIds(getAllIds(nodes)), [nodes]);
  const collapseAll = useCallback(() => setExpandedIds(new Set()), []);

  const searchLower = searchQuery.trim().toLowerCase();
  const filteredNodes = filterTree(nodes, statusFilter, searchLower);
  const effectiveExpandedIds = searchLower ? getAllIds(nodes) : expandedIds;

  return (
    <div className="flex flex-col gap-2" data-testid="rcdo-tree-view">
      <div className="flex gap-2">
        <Button type="button" variant="ghost" size="sm" onClick={expandAll} aria-label="Expand all nodes" className="h-7 px-2 text-xs border border-border">Expand all</Button>
        <Button type="button" variant="ghost" size="sm" onClick={collapseAll} aria-label="Collapse all nodes" className="h-7 px-2 text-xs border border-border">Collapse all</Button>
      </div>
      <ul role="tree" aria-label="RCDO hierarchy" className="m-0 p-0 list-none">
        {filteredNodes.length === 0 ? (
          <li className="py-4 text-center text-sm text-muted">No nodes match the current filter.</li>
        ) : (
          filteredNodes.map((node) => (
            <TreeNodeItem key={node.id} node={node} depth={0} selectedId={selectedId} expandedIds={effectiveExpandedIds} onSelect={onSelect} onToggleExpand={toggleExpand} />
          ))
        )}
      </ul>
    </div>
  );
}

/**
 * RCDO management page.
 * Route: /weekly/rcdos
 */
import { useState, useCallback } from "react";
import { Skeleton } from "../components/ui/Skeleton.js";
import { Target, Network } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Input } from "../components/ui/Input.js";
import { Badge } from "../components/ui/Badge.js";
import { useHostContext } from "../host/HostProvider.js";
import { EmptyState } from "../components/shared/EmptyState.js";
import { useRcdoTree, useRcdoApi } from "../api/rcdoHooks.js";
import { RcdoTreeView, type StatusFilter } from "../components/rcdo/RcdoTreeView.js";
import { RcdoBreadcrumb } from "../components/rcdo/RcdoBreadcrumb.js";
import { RcdoNodeForm } from "../components/rcdo/RcdoNodeForm.js";
import { ArchiveConfirmDialog } from "../components/rcdo/ArchiveConfirmDialog.js";
import { MoveNodeDialog } from "../components/rcdo/MoveNodeDialog.js";
import type { RcdoTreeNode, RcdoNodeType } from "../api/rcdoTypes.js";

interface RcdoPermissions {
  readonly canCreateRallyCry: boolean; readonly canEditRallyCry: boolean;
  readonly canCreateDO: boolean; readonly canEditDO: boolean;
  readonly canCreateOutcome: boolean; readonly canEditOutcome: boolean;
  readonly canArchive: boolean; readonly canMove: boolean; readonly isReadOnly: boolean;
}

function useRcdoPermissions(): RcdoPermissions {
  const { featureFlags } = useHostContext();
  const isAdmin = Boolean(featureFlags.rcdoAdminEnabled);
  const isManager = featureFlags.managerReviewEnabled;
  return {
    canCreateRallyCry: isAdmin, canEditRallyCry: isAdmin,
    canCreateDO: isAdmin || isManager, canEditDO: isAdmin || isManager,
    canCreateOutcome: isAdmin || isManager, canEditOutcome: isAdmin || isManager,
    canArchive: isAdmin || isManager, canMove: isAdmin || isManager,
    isReadOnly: !isAdmin && !isManager,
  };
}

function findNodePath(nodes: RcdoTreeNode[], targetId: string, currentPath: RcdoTreeNode[] = []): RcdoTreeNode[] {
  for (const node of nodes) {
    const path = [...currentPath, node];
    if (node.id === targetId) return path;
    const found = findNodePath(node.children, targetId, path);
    if (found.length > 0) return found;
  }
  return [];
}

function findNode(nodes: RcdoTreeNode[], targetId: string): RcdoTreeNode | null {
  for (const node of nodes) {
    if (node.id === targetId) return node;
    const found = findNode(node.children, targetId);
    if (found) return found;
  }
  return null;
}

function hasActiveChildren(node: RcdoTreeNode): boolean {
  return node.children.some((child) => child.status !== "ARCHIVED" || hasActiveChildren(child));
}

type PanelMode = "empty" | "detail" | "create" | "edit";

const STATUS_BADGE_VARIANT: Record<string, "success" | "draft" | "default"> = {
  ACTIVE: "success", DRAFT: "draft", ARCHIVED: "default",
};

export default function Rcdos() {
  const perms = useRcdoPermissions();
  const api = useRcdoApi();
  const { data: tree, loading, error, refetch } = useRcdoTree();

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [panelMode, setPanelMode] = useState<PanelMode>("empty");
  const [createNodeType, setCreateNodeType] = useState<RcdoNodeType | null>(null);
  const [createParentId, setCreateParentId] = useState<string | null>(null);
  const [showArchiveDialog, setShowArchiveDialog] = useState(false);
  const [showMoveDialog, setShowMoveDialog] = useState(false);
  const [dialogSubmitting, setDialogSubmitting] = useState(false);
  const [actionError, setActionError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");

  const nodes = tree ?? [];
  const selectedNode = selectedId ? findNode(nodes, selectedId) : null;
  const selectedPath = selectedId ? findNodePath(nodes, selectedId) : [];

  const handleSelect = useCallback((id: string) => { setSelectedId(id); setPanelMode("detail"); setActionError(null); }, []);
  const handleBreadcrumbNavigate = useCallback((id: string) => { setSelectedId(id); setPanelMode("detail"); setActionError(null); }, []);

  function openCreate(nodeType: RcdoNodeType, parentId?: string) {
    setCreateNodeType(nodeType); setCreateParentId(parentId ?? null);
    setPanelMode("create"); setActionError(null);
  }

  async function handleCreate(payload: Parameters<ReturnType<typeof useRcdoApi>["createNode"]>[0]) {
    const created = await api.createNode(payload);
    refetch(); setSelectedId(created.id); setPanelMode("detail");
  }

  function openEdit() { if (!selectedNode) return; setPanelMode("edit"); setActionError(null); }

  async function handleEdit(payload: Parameters<ReturnType<typeof useRcdoApi>["updateNode"]>[1]) {
    if (!selectedId) return;
    await api.updateNode(selectedId, payload); refetch(); setPanelMode("detail");
  }

  async function handleArchiveConfirm() {
    if (!selectedId) return;
    setDialogSubmitting(true);
    try { await api.archiveNode(selectedId); refetch(); setShowArchiveDialog(false); setPanelMode("empty"); setSelectedId(null); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Archive failed"); setShowArchiveDialog(false); }
    finally { setDialogSubmitting(false); }
  }

  async function handleMoveConfirm(newParentId: string) {
    if (!selectedId) return;
    setDialogSubmitting(true);
    try { await api.moveNode(selectedId, newParentId); refetch(); setShowMoveDialog(false); setPanelMode("detail"); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Move failed"); setShowMoveDialog(false); }
    finally { setDialogSubmitting(false); }
  }

  async function handleActivate() {
    if (!selectedId) return;
    setActionError(null);
    try { await api.activateNode(selectedId); refetch(); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Activate failed"); }
  }

  function canEditSelected(): boolean {
    if (!selectedNode) return false;
    switch (selectedNode.nodeType) {
      case "RALLY_CRY": return perms.canEditRallyCry;
      case "DEFINING_OBJECTIVE": return perms.canEditDO;
      case "OUTCOME": return perms.canEditOutcome;
    }
  }

  return (
    <div className="flex flex-col gap-4 h-full" data-testid="page-rcdos">
      {/* Page heading */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">RCDO Hierarchy</h2>
        {!perms.isReadOnly && (
          <div className="flex gap-2 flex-wrap">
            {perms.canCreateRallyCry && (
