/**
 * InsightPanel — displays AI-generated insight cards for a team week
 * (mode='team') or a personal plan (mode='personal').
 *
 * Uses balanced text layout: each card's paragraph is shrinkwrapped to
 * the tightest width that doesn't add extra lines, so line lengths are
 * roughly equal instead of ragged-right. See lib/useBalancedText.ts.
 */
import { useMemo } from "react";
import { Bot } from "lucide-react";
import { Badge } from "../ui/Badge.js";
import { Skeleton } from "../ui/Skeleton.js";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useTeamInsights, usePlanInsights } from "../../api/ragHooks.js";
import { useBalancedText } from "../../lib/useBalancedText.js";
import type { InsightCard } from "../../api/ragApi.js";

// ── Balanced text config ──────────────────────────────────────────────────────
// Must be a named font (not system-ui) for accurate canvas measurement.
// Matches the `text-sm` class on the insight text <p> (14px Inter).
const INSIGHT_FONT = '14px "Inter", sans-serif';

// ── Severity helpers ──────────────────────────────────────────────────────────

type SeverityLevel = "HIGH" | "MEDIUM" | "LOW";

function severityBadgeVariant(
  severity: string,
): "danger" | "warning" | "primary" | "default" {
  switch (severity.toUpperCase() as SeverityLevel) {
    case "HIGH":
      return "danger";
    case "MEDIUM":
      return "warning";
    case "LOW":
      return "primary";
    default:
      return "default";
  }
}

function severityLabel(severity: string): string {
  return severity.charAt(0).toUpperCase() + severity.slice(1).toLowerCase();
}

// ── Individual card ───────────────────────────────────────────────────────────

function InsightCardItem({
  card,
  balancedWidth,
}: {
  card: InsightCard;
  balancedWidth: number | undefined;
}) {
  return (
    <div
      className={cn(
        "rounded-default border border-border bg-surface px-4 py-3 flex flex-col gap-2",
      )}
      data-testid={`insight-card-${card.suggestionId}`}
    >
      {/* Header row: severity + feedback buttons */}
      <div className="flex items-center justify-between gap-2">
        <Badge
          variant={severityBadgeVariant(card.severity)}
          className="text-[0.65rem] capitalize"
          data-testid={`insight-severity-${card.suggestionId}`}
        >
          {severityLabel(card.severity)}
        </Badge>
        <AiFeedbackButtons suggestionId={card.suggestionId} />
      </div>

      {/* Insight text — balanced via Pretext shrinkwrap measurement */}
      <p
        className="m-0 text-sm text-foreground leading-relaxed"
        style={balancedWidth != null ? { maxWidth: balancedWidth } : undefined}
        data-testid={`insight-text-${card.suggestionId}`}
      >
        {card.insightText}
      </p>

      {/* Action suggestion */}
      {card.actionSuggestion && (
        <p
          className="m-0 text-xs text-muted italic"
          data-testid={`insight-action-${card.suggestionId}`}
        >
          → {card.actionSuggestion}
        </p>
      )}

      {/* Source entity IDs are internal UUIDs — not surfaced to the user */}
    </div>
  );
}

// ── Skeleton loading cards ────────────────────────────────────────────────────

function InsightSkeletons() {
  return (
    <div
      className="flex flex-col gap-3"
      data-testid="insight-panel-loading"
      aria-busy="true"
    >
      {[0, 1, 2].map((i) => (
        <div
          key={i}
          className="rounded-default border border-border px-4 py-3 flex flex-col gap-2"
        >
          <Skeleton className="h-4 w-16" />
          <Skeleton className="h-3.5 w-full" />
          <Skeleton className="h-3.5 w-4/5" />
          <Skeleton className="h-3 w-2/3" />
        </div>
      ))}
    </div>
  );
}

// ── Balanced insight card list ─────────────────────────────────────────────────

/**
 * Renders a list of insight cards with Pretext-balanced text.
 * The `ref` from `useBalancedText` is attached to the container so it
 * re-measures when the panel resizes (e.g. sidebar toggle, window resize).
 */
function BalancedInsightCardList({ insights }: { insights: InsightCard[] }) {
  const insightTexts = useMemo(
    () => insights.map((c) => c.insightText),
    [insights],
  );

  const { ref, widths } = useBalancedText(insightTexts, INSIGHT_FONT);

  return (
    <div ref={ref} className="flex flex-col gap-3">
      {insights.map((card) => (
        <InsightCardItem
          key={card.suggestionId}
          card={card}
          balancedWidth={widths.get(card.insightText)}
        />
      ))}
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface InsightPanelTeamProps {
  mode: "team";
  teamId?: string;
  weekStart?: string;
  planId?: never;
}

interface InsightPanelPersonalProps {
  mode: "personal";
  planId?: string;
  teamId?: never;
  weekStart?: never;
}

type InsightPanelProps = InsightPanelTeamProps | InsightPanelPersonalProps;

function TeamInsightPanel({
  teamId,
  weekStart,
}: {
  teamId?: string;
  weekStart?: string;
}) {
  const { data, loading, error } = useTeamInsights(
    teamId ?? null,
    weekStart ?? "",
  );

  if (loading) return <InsightSkeletons />;

  if (error) {
    return (
      <p
        className="text-sm text-danger"
        data-testid="insight-panel-error"
      >
        Failed to load insights: {error.message}
      </p>
    );
  }

  if (!data?.aiAvailable) {
    return (
      <div
        className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic"
        data-testid="insight-panel-unavailable"
      >
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI insights are currently unavailable.
      </div>
    );
  }

  if (data.insights.length === 0) {
    return (
      <p
        className="text-sm text-muted"
        data-testid="insight-panel-empty"
      >
        No AI insights available for this period.
      </p>
    );
  }

  return <BalancedInsightCardList insights={data.insights} />;
}

function PersonalInsightPanel({ planId }: { planId?: string }) {
  const { data, loading, error } = usePlanInsights(planId ?? null);

  if (loading) return <InsightSkeletons />;

  if (error) {
    return (
      <p
        className="text-sm text-danger"
        data-testid="insight-panel-error"
      >
        Failed to load insights: {error.message}
      </p>
    );
  }

  if (!data?.aiAvailable) {
    // Silently hide when AI not available — avoids noise in consolidated sections
    return null;
  }

  if (data.insights.length === 0) {
    // Return null when empty — parent section handles the "nothing here" state
    return null;
  }

  return <BalancedInsightCardList insights={data.insights} />;
}

/**
 * InsightPanel renders AI-generated insight cards with balanced text layout.
 *
 * Uses canvas-based text measurement (lib/useBalancedText.ts) to compute a
 * shrinkwrapped max-width that distributes words evenly across lines,
 * eliminating the short trailing "orphan" line typical of ragged-right text.
 *
 * Set `mode="team"` with `teamId` + `weekStart` for team-level insights, or
 * `mode="personal"` with `planId` for plan-level personal insights.
 */
export function InsightPanel(props: InsightPanelProps) {
  return (
    <div data-testid="insight-panel">
      {props.mode === "team" ? (
        <TeamInsightPanel
          {...(props.teamId !== undefined && { teamId: props.teamId })}
          {...(props.weekStart !== undefined && { weekStart: props.weekStart })}
        />
      ) : (
        <PersonalInsightPanel
          {...(props.planId !== undefined && { planId: props.planId })}
        />
      )}
    </div>
  );
}

/**
 * SemanticSearchInput — text input + submit that executes a RAG query
 * and renders the answer in a QueryAnswerCard below the input.
 */
import { useCallback, useRef, useState } from "react";
import { Bot, RotateCcw, Search, MessageCircle } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Input } from "../ui/Input.js";

import { cn } from "../../lib/utils.js";
import { useStreamingRagQuery } from "../../api/ragStreamHooks.js";
import { QueryAnswerCard } from "./QueryAnswerCard.js";

const SUGGESTED_QUESTIONS = [
  "What did the team commit to last week?",
  "Which RCDOs received the most effort this month?",
  "What are the recurring carry-forward patterns?",
  "Which team members are overcommitting?",
  "What KING/QUEEN work was achieved last week?",
] as const;

interface SemanticSearchInputProps {
  teamId?: string;
  userId?: string;
  className?: string;
}

export function SemanticSearchInput({
  teamId,
  userId,
  className,
}: SemanticSearchInputProps) {
  const [question, setQuestion] = useState("");
  const {
    answer,
    sources,
    confidence,
    isStreaming,
    error,
    startStream,
    cancel,
  } = useStreamingRagQuery(teamId ?? "", userId ?? "");

  // Treat "has received any answer content" as equivalent to batch data availability
  const hasAnswer = answer.length > 0;
  const loading = isStreaming && !hasAnswer;
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = useCallback(
    (e: React.FormEvent) => {
      e.preventDefault();
      const q = question.trim();
      if (!q) return;
      startStream(q);
    },
    [question, startStream],
  );

  const handleRetry = useCallback(() => {
    const q = question.trim();
    if (!q) return;
    cancel();
    startStream(q);
  }, [question, startStream, cancel]);

  return (
    <div className={cn("rounded-default border border-border bg-surface p-4 flex flex-col gap-3", className)}>
      {/* Header + form on one line */}
      <div className="flex items-center gap-2">
        <Bot className="h-4 w-4 text-primary shrink-0" aria-hidden="true" />
        <span className="text-sm font-semibold text-foreground whitespace-nowrap">
          Ask AI about your team&apos;s work
        </span>
      </div>

      <form onSubmit={(e) => void handleSubmit(e)} className="flex gap-2">
        <Input
          ref={inputRef}
          data-testid="semantic-search-input"
          value={question}
          onChange={(e) => setQuestion(e.target.value)}
          placeholder="e.g. What did the team commit to last week?"
          icon={<Search className="h-3.5 w-3.5" />}
          disabled={loading}
          className="flex-1"
          aria-label="Ask a question about your team's work history"
        />
        <Button
          type="submit"
          variant="primary"
          size="md"
          disabled={loading || question.trim().length === 0}
          data-testid="semantic-search-submit"
          aria-label="Submit question"
        >
          {loading ? (
            <span className="inline-flex items-center gap-1.5">
              <span
                className="h-3.5 w-3.5 rounded-full border-2 border-white/30 border-t-white animate-spin"
                aria-hidden="true"
              />
              Searching…
            </span>
          ) : (
            <>
              <Search className="h-3.5 w-3.5" />
              Search
            </>
          )}
        </Button>
      </form>

      {/* Suggested questions — shown when input is empty and no result */}
      {!question.trim() && !hasAnswer && !loading && !error && (
        <div className="flex flex-wrap gap-1.5" data-testid="suggested-questions">
          <span className="text-[0.65rem] text-muted flex items-center gap-1 mr-1">
            <MessageCircle className="h-3 w-3" /> Try asking:
          </span>
          {SUGGESTED_QUESTIONS.map((q) => (
            <button
              key={q}
              type="button"
              onClick={() => {
                setQuestion(q);
                startStream(q);
              }}
              className="inline-flex items-center rounded-full border border-primary/20 bg-primary/5 px-2.5 py-1 text-[0.65rem] text-primary hover:bg-primary/10 hover:border-primary/40 transition-colors cursor-pointer"
              data-testid={`suggested-q-${q.slice(0, 20).replace(/\s/g, "-").toLowerCase()}`}
            >
              {q}
            </button>
          ))}
        </div>
      )}

      {/* Loading state */}
      {loading && (
        <div
          className="flex items-center gap-2 text-sm text-muted animate-pulse"
          data-testid="semantic-search-loading"
          role="status"
          aria-live="polite"
        >
          <Bot className="h-4 w-4 shrink-0" aria-hidden="true" />
          Searching your team&apos;s planning history…
        </div>
      )}

      {/* Error state */}
      {!loading && error && (
        <div
          className="flex items-center justify-between gap-2 rounded-default border border-danger/30 bg-danger/5 px-3 py-2.5"
          data-testid="semantic-search-error"
          role="alert"
        >
          <span className="text-sm text-danger">{error}</span>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleRetry}
            data-testid="semantic-search-retry"
            aria-label="Retry search"
          >
            <RotateCcw className="h-3.5 w-3.5" />
            Retry
          </Button>
        </div>
      )}

      {/* Answer card — streaming mode: shown as soon as any content arrives */}
      {(hasAnswer || isStreaming) && !error && (
        <QueryAnswerCard
          answer={answer}
          sources={sources}
          confidence={confidence}
          suggestionId=""
          streaming={true}
          isStreaming={isStreaming}
          data-testid="semantic-search-answer"
        />
      )}

      {/* AI unavailable — the streaming error callback covers this case via the
          error state rendered above. No additional block needed. */}
    </div>
  );
}

